define("local_pathwaynav/progress_bar",["core/log"],(function(log){return{init:function(){var container=document.querySelector("#lpwbar-container");if(!container){log.debug("local_pathwaynav/progress_bar: Container not found.");return}var activeStep=container.querySelector(".lpwbar-step-active");if(activeStep){var stepsNav=container.querySelector(".lpwbar-steps");if(stepsNav){setTimeout((function(){activeStep.scrollIntoView({behavior:"smooth",block:"nearest",inline:"center"})}),100)}}var lastScrollY=window.scrollY;var ticking=!1;var onScroll=function(){if(!ticking){window.requestAnimationFrame((function(){var currentScrollY=window.scrollY;if(currentScrollY>lastScrollY&&currentScrollY>100){container.classList.add("lpwbar-hidden")}else{container.classList.remove("lpwbar-hidden")}lastScrollY=currentScrollY;ticking=!1}));ticking=!0}};window.addEventListener("scroll",onScroll,{passive:!0})}}}));
